// Token endpoint
app.post('/token', async (req, res) => {
  if (!requireParams(req, res, ['grant_type'])) return;

  const auth = await authenticateClient(req);
  if (!auth) {
    res.set('WWW-Authenticate', 'Basic realm="oauth"');
    return res.status(401).json({ error: 'invalid_client' });
  }

  const { clientId, client } = auth;
  const grantType = req.body.grant_type;

  if (!client.grants.includes(grantType)) {
    return res.status(400).json({ error: 'unsupported_grant_type' });
  }

  if (grantType === 'authorization_code') {
    if (!requireParams(req, res, ['code', 'redirect_uri'])) return;

    const code = req.body.code;
    const redirectUri = req.body.redirect_uri;

    const data = await consumeAuthCode(code);
    if (!data) return res.status(400).json({ error: 'invalid_grant' });

    if (data.client_id !== clientId) return res.status(400).json({ error: 'invalid_grant' });
    if (data.redirect_uri !== redirectUri) return res.status(400).json({ error: 'invalid_grant' });

    const { token: access_token, expires_in } = issueAccessToken({
      sub: data.sub,
      clientId,
      scope: data.scope,
    });

    const refresh_token = randomToken(48);
    await storeRefreshToken({ refreshToken: refresh_token, sub: data.sub, clientId, scope: data.scope });

    return res.json({
      token_type: 'Bearer',
      access_token,
      expires_in,
      refresh_token,
      scope: data.scope || '',
    });
  }

  if (grantType === 'refresh_token') {
    if (!requireParams(req, res, ['refresh_token'])) return;

    const refreshToken = req.body.refresh_token;
    const data = await getRefreshToken(refreshToken);
    if (!data) return res.status(400).json({ error: 'invalid_grant' });

    if (data.client_id !== clientId) return res.status(400).json({ error: 'invalid_grant' });

    const { token: access_token, expires_in } = issueAccessToken({
      sub: data.sub,
      clientId,
      scope: data.scope,
    });

    // Reuse refresh token without rotation; do not change TTL (or optionally extend)
    return res.json({
      token_type: 'Bearer',
      access_token,
      expires_in,
      refresh_token: refreshToken,
      scope: data.scope || '',
    });
  }

  return res.status(400).json({ error: 'unsupported_grant_type' });
});

